<div class="d-flex justify-content-between mb-2"><h1 class="h5">Productos y servicios</h1><a href="/app/productos/crear" class="btn btn-primary btn-sm">Nuevo producto</a></div><form class="mb-2"><input class="form-control form-control-sm" name="q" value="<?= e($buscar) ?>" placeholder="Buscar producto"></form><table class="table table-sm"><thead><tr><th>Código</th><th>Nombre</th><th>Precio</th><th>Impuesto</th><th>Estado</th></tr></thead><tbody><?php foreach($productos as $p): ?><tr><td><?= e($p['codigo']) ?></td><td><?= e($p['nombre']) ?></td><td>$<?= number_format((float)$p['precio'],2) ?></td><td><?= e((string)$p['impuesto']) ?>%</td><td><?= e($p['estado']) ?></td></tr><?php endforeach; ?></tbody></table>
